
-- Create legal_documents table
CREATE TABLE public.legal_documents (
  slug TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  content TEXT NOT NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.legal_documents ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read legal docs" ON public.legal_documents
  FOR SELECT TO public USING (true);

CREATE POLICY "Admins can manage legal docs" ON public.legal_documents
  FOR ALL TO authenticated
  USING (public.has_role(auth.uid(), 'admin'::app_role))
  WITH CHECK (public.has_role(auth.uid(), 'admin'::app_role));

-- Seed initial content
INSERT INTO public.legal_documents (slug, title, content) VALUES
('terms', 'Termos de Uso', E'# Termos de Uso da ArtisCase\n\n**Última atualização:** Março de 2026\n\nBem-vindo à ArtisCase! Ao acessar e utilizar nossa plataforma, você concorda com os termos e condições descritos abaixo. Leia atentamente.\n\n## 1. Objeto da Plataforma\n\nA ArtisCase é uma plataforma de e-commerce especializada na venda de capas (cases) personalizadas para smartphones. Oferecemos um sistema de personalização com inteligência artificial que permite ao usuário transformar suas fotos em obras de arte únicas.\n\n## 2. Cadastro e Conta\n\n- Para realizar compras e utilizar recursos de personalização, é necessário criar uma conta com nome, e-mail e senha, ou autenticar-se via Google.\n- O usuário é responsável pela veracidade das informações fornecidas e pela segurança de suas credenciais.\n- Ao se cadastrar, o usuário recebe ArtisCoins de bônus para utilizar nas funcionalidades de IA.\n\n## 3. ArtisCoins e Personalização com IA\n\n- ArtisCoins são a moeda virtual da plataforma, utilizadas para aplicar filtros artísticos de IA e upscale de imagens.\n- ArtisCoins podem ser obtidas via bônus de cadastro, indicação de amigos ou compra direta.\n- ArtisCoins possuem prazo de validade e não são reembolsáveis nem transferíveis.\n- O custo em ArtisCoins de cada funcionalidade é exibido antes da confirmação.\n\n## 4. Processo de Compra\n\n- O usuário seleciona o modelo de celular, personaliza a capa com sua imagem e prossegue para o checkout.\n- Os pagamentos são processados de forma segura via Stripe (cartão de crédito: Visa, Mastercard, Elo, Amex) ou Pix.\n- Os preços são exibidos em Reais (BRL) e incluem o valor do produto. O frete é calculado separadamente com base no CEP de entrega.\n\n## 5. Produção e Envio\n\n- Após a confirmação do pagamento, a produção da capa é iniciada com prazo estimado de 48 horas úteis.\n- O envio é realizado para todo o Brasil. O prazo e custo do frete dependem da localidade do destinatário.\n- Um código de rastreamento será disponibilizado na área "Meus Pedidos" assim que o produto for despachado.\n\n## 6. Trocas e Cancelamentos\n\n- Conforme o Código de Defesa do Consumidor (CDC), o cliente tem direito de arrependimento em até 7 dias corridos após o recebimento do produto.\n- Produtos com defeitos de fabricação serão substituídos sem custo adicional.\n- Não realizamos trocas por insatisfação com a imagem personalizada, desde que esta corresponda à prévia aprovada pelo cliente no checkout.\n\n## 7. Propriedade Intelectual\n\n- As imagens enviadas pelo usuário são de sua inteira responsabilidade. O usuário declara possuir os direitos sobre as imagens utilizadas.\n- A ArtisCase não se responsabiliza por violações de direitos autorais decorrentes de imagens enviadas pelos usuários.\n- As imagens processadas pela IA são armazenadas de forma segura e utilizadas exclusivamente para a produção do pedido.\n\n## 8. Limitação de Responsabilidade\n\n- A ArtisCase não garante disponibilidade ininterrupta da plataforma.\n- Não nos responsabilizamos por atrasos de entrega causados por transportadoras ou fatores externos.\n- Os resultados dos filtros de IA podem variar e são apresentados como prévia antes da confirmação.\n\n## 9. Alterações nos Termos\n\nReservamo-nos o direito de alterar estes Termos de Uso a qualquer momento. As alterações entram em vigor na data de sua publicação na plataforma.\n\n## 10. Foro\n\nFica eleito o foro da comarca de domicílio do consumidor para dirimir quaisquer controvérsias, conforme o art. 101, I do CDC.\n\n---\n\nDúvidas? Entre em contato pela seção "Solicitar Modelo" em nosso site.'),
('privacy', 'Política de Privacidade', E'# Política de Privacidade da ArtisCase\n\n**Última atualização:** Março de 2026\n\nA ArtisCase valoriza a privacidade dos seus usuários. Esta Política descreve como coletamos, utilizamos, armazenamos e protegemos seus dados pessoais, em conformidade com a Lei Geral de Proteção de Dados (LGPD — Lei nº 13.709/2018).\n\n## 1. Dados Coletados\n\nColetamos os seguintes dados pessoais:\n\n- **Dados de cadastro:** nome completo, endereço de e-mail, senha (criptografada) e telefone (opcional).\n- **Dados de entrega:** endereço completo (rua, número, complemento, bairro, cidade, estado e CEP).\n- **Dados de personalização:** imagens enviadas pelo usuário para customização das capas.\n- **Dados de navegação:** páginas visitadas, interações na plataforma e dados de sessão (coletados via Microsoft Clarity).\n- **Dados de pagamento:** processados diretamente pelo Stripe. A ArtisCase não armazena dados de cartão de crédito.\n\n## 2. Finalidade do Tratamento\n\nUtilizamos seus dados para:\n\n- Criar e gerenciar sua conta na plataforma.\n- Processar e entregar seus pedidos.\n- Aplicar filtros de IA nas imagens enviadas.\n- Calcular frete e gerenciar entregas.\n- Enviar notificações sobre o status dos pedidos por e-mail.\n- Melhorar a experiência do usuário e a performance da plataforma (analytics).\n- Gerenciar o programa de ArtisCoins e indicações.\n\n## 3. Cookies e Ferramentas de Analytics\n\n- Utilizamos o **Microsoft Clarity** para análise de comportamento e mapa de calor, com o objetivo de melhorar a usabilidade da plataforma.\n- Cookies essenciais são utilizados para manter a sessão do usuário autenticada.\n- Não utilizamos cookies de publicidade ou remarketing.\n\n## 4. Compartilhamento de Dados\n\nSeus dados podem ser compartilhados com:\n\n- **Stripe:** para processamento seguro de pagamentos.\n- **Serviços de envio:** endereço de entrega para despacho dos pedidos.\n- **Provedores de infraestrutura:** serviços de hospedagem e banco de dados (Lovable Cloud).\n\nNão vendemos, alugamos ou compartilhamos seus dados pessoais com terceiros para fins de marketing.\n\n## 5. Armazenamento e Segurança\n\n- Os dados são armazenados em servidores seguros com criptografia em trânsito (HTTPS/TLS).\n- Imagens enviadas são armazenadas em buckets privados com acesso restrito ao proprietário.\n- Senhas são armazenadas com hash criptográfico (bcrypt).\n- Implementamos políticas de segurança em nível de linha (RLS) para garantir que cada usuário acesse apenas seus próprios dados.\n\n## 6. Retenção de Dados\n\n- Dados de conta e perfil são mantidos enquanto a conta estiver ativa.\n- Imagens de personalização são mantidas pelo período necessário à produção e eventual suporte pós-venda.\n- O usuário pode solicitar a exclusão de sua conta e dados a qualquer momento pela página de Perfil.\n\n## 7. Direitos do Titular (LGPD)\n\nVocê tem direito a:\n\n- **Acesso:** consultar seus dados pessoais armazenados.\n- **Correção:** atualizar dados incompletos ou incorretos.\n- **Eliminação:** solicitar a exclusão de seus dados pessoais.\n- **Portabilidade:** solicitar seus dados em formato estruturado.\n- **Revogação do consentimento:** retirar o consentimento a qualquer momento.\n\nPara exercer seus direitos, acesse a página de Perfil ou entre em contato conosco.\n\n## 8. Menores de Idade\n\nA plataforma não é destinada a menores de 18 anos. Caso identifiquemos dados de menores, estes serão excluídos.\n\n## 9. Alterações nesta Política\n\nEsta Política pode ser atualizada periodicamente. A data da última atualização será sempre exibida no topo do documento.\n\n## 10. Contato\n\nPara dúvidas sobre privacidade e proteção de dados, utilize a seção "Solicitar Modelo" em nosso site.\n\n---\n\nAo utilizar a ArtisCase, você declara ter lido e concordado com esta Política de Privacidade.');
